      {/* Search */}
      <div className="mb-6 max-w-md">
        <input type="text" value={searchQuery}
          onChange={(e) => { setSearchQuery(e.target.value); setSelectedCat(null) }}
          placeholder="Buscá productos..."
          className="w-full rounded-lg border border-input bg-surface px-4 py-2.5 text-sm text-foreground outline-none focus:border-ring"
        />
      </div>

