import { useState, useEffect } from "react"

export function PrivacyModeToggle() {
  const [active, setActive] = useState(false)

  useEffect(() => {
    try {
      const saved = localStorage.getItem("fun4me_privacy_mode")
      if (saved === "true") {
        setActive(true)
        document.documentElement.classList.add("privacy-mode")
      }
    } catch {}
  }, [])

  const toggle = () => {
    const next = !active
    setActive(next)
    try { localStorage.setItem("fun4me_privacy_mode", next ? "true" : "false") } catch {}
    document.documentElement.classList.toggle("privacy-mode", next)
  }

  return (
    <button onClick={toggle}
      className={`flex h-9 w-9 items-center justify-center rounded-md transition-all hover:bg-surface-light ${
        active ? "text-accent" : "text-muted-foreground"
      }`}
      title={active ? "Modo privado activo" : "Activar modo privado"}>
      {active ? (
        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="[REDACTED_PHONE]" fill="none" stroke="currentColor" strokeWidth="2">
          <rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a[REDACTED_PHONE]v4"/>
